        if (sat[a] != sat[b]) return sat[a] > sat[b];
        return graph[a].size() > graph[b].size();
    };
    set<int, decltype(cmp)> pq(cmp);
    for (int i = 0; i < n; ++i) pq.insert(i);
    int max_color = 0;
    while (!pq.empty()) {
