            int new_single = -1;
            if (!in_C[to] && new_domain == 1) {
                new_single = singleton_color(to);
            }
            if (!in_C[to]) {
                add_blocking(to, old_single, new_single);
            }
        }
    }

    int uncolored_degree(int v) const {
        int result = 0;
        for (int to : graph[v]) {
            if (!in_C[to]) {
                ++result;
            }
        }
        return result;
    }

    int UVERTEX() {
// start
        // Select uncolored vertex with smallest domain size (most constrained) to reduce branching.
        int best = -1;
        int best_domain = numeric_limits<int>::max();
        int best_degree = -1;
        for (int v = 0; v < n; ++v) {
            if (in_C[v]) continue;
            int d = domain_size[v];
            if (d < best_domain || (d == best_domain && degree[v] > best_degree)) {
                best_domain = d;
                best_degree = degree[v];
                best = v;
            }
        }
        if (best == -1) {
            // fallback: pick any uncolored vertex
            for (int v = 0; v < n; ++v) {
                if (!in_C[v]) { best = v; break; }
            }
        }
        return best;
    }

    int CVERTEX() {
// start
        // Choose vertex with largest domain (most flexibility) to uncolour, to increase chance of finding alternative.
        int best_domain = -1;
        int best_degree = -1;
        vector<int> candidates;
        for (int v = 0; v < n; ++v) {
            if (!in_C[v]) continue;
            if (domain_size[v] > best_domain) {
                best_domain = domain_size[v];
                best_degree = degree[v];
                candidates.clear();
                candidates.push_back(v);
            } else if (domain_size[v] == best_domain) {
                if (degree[v] > best_degree) {
                    best_degree = degree[v];
                    candidates.clear();
                    candidates.push_back(v);
                } else if (degree[v] == best_degree) {
                    candidates.push_back(v);
                }
            }
        }
        if (candidates.empty()) {
            // fallback: pick any colored vertex
            for (int v = 0; v < n; ++v) {
                if (in_C[v]) { candidates.push_back(v); break; }
            }
        }
        uniform_int_distribution<int> dist(0, static_cast<int>(candidates.size()) - 1);
        return candidates[dist(rng)];
    }

    vector<int> build_D(int u) const {
        vector<int> result;
        for (int c = 0; c < k; ++c) {
            if (forbidden[u][c] == 0 && bad(u, c) == 0) {
                result.push_back(c);
            }
        }
        return result;
    }

    int COLOUR(int u, const vector<int>& D) {
// start
        if (D.empty()) {
            return -1;
        }
        // Prefer the remembered color if available, otherwise pick the least used color globally.
        int remembered_color = remembered[u];
        for (int c : D) {
            if (c == remembered_color) {
                return c;
            }
        }
        // If remembered color not available, pick the color that appears least among neighbours (to reduce future conflicts).
        // Use a simple heuristic: count how many neighbours already have each color.
        vector<int> color_count(k, 0);
        for (int to : graph[u]) {
            if (in_C[to]) {
                int col = colouring[to];
                if (col >= 0 && col < k) {
                    color_count[col]++;
                }
            }
        }
        int best_c = D[0];
        int best_count = numeric_limits<int>::max();
        for (int c : D) {
            if (color_count[c] < best_count) {
                best_count = color_count[c];
                best_c = c;
            }
        }
        return best_c;
    }

    pair<int, vector<int>> FCNS(int B, int max_steps) {
        int steps = 0;
        while (steps < max_steps) {
            if (U_size() == 0) {
                break;
            }

            int u = UVERTEX();
            if (u < 0) {
                break;
            }

            vector<int> D = build_D(u);
            if (!D.empty()) {
                int c = COLOUR(u, D);
                colour_vertex_and_update_domains(u, c);
            } else {
                int limit = min(B, C_size());
                for (int i = 0; i < limit; ++i) {
                    int c_vertex = CVERTEX();
                    if (c_vertex < 0) {
                        break;
                    }
                    uncolour_vertex_and_update_domains(c_vertex);
                    colour_prefers_different = true;
                }
            }

            ++steps;
        }

        vector<int> result = colouring;
        int used_colors = 0;
        vector<int> remap(k, -1);
        for (int v = 0; v < n; ++v) {
            if (result[v] < 0) {
                continue;
            }
            if (remap[result[v]] == -1) {
                remap[result[v]] = used_colors++;
            }
            result[v] = remap[result[v]];
        }
        return {used_colors, result};
    }
};

vector<int> greedy_coloring(const vector<vector<int>>& graph) {
// start
        int n = static_cast<int>(graph.size());
        vector<int> color(n, -1);
        // Use DSATUR-like heuristic: pick vertex with highest saturation degree (number of different colors among neighbours).
        vector<int> sat_degree(n, 0);
        vector<set<int>> neighbor_colors(n);
        vector<int> degree(n);
        for (int i = 0; i < n; ++i) {
            degree[i] = static_cast<int>(graph[i].size());
        }
        // Priority queue: ( -sat_degree, -degree, vertex )
        set<pair<pair<int,int>, int>> pq;
        for (int i = 0; i < n; ++i) {
            pq.insert({{-sat_degree[i], -degree[i]}, i});
        }
        int used_colors = 0;
        while (!pq.empty()) {
            auto it = pq.begin();
            int v = it->second;
            pq.erase(it);
            // Find smallest color not used by neighbours
            vector<bool> used(used_colors + 1, false);
            for (int to : graph[v]) {
                if (color[to] != -1) {
                    int c = color[to];
                    if (c < (int)used.size()) used[c] = true;
                }
            }
            int chosen = 0;
            while (chosen < (int)used.size() && used[chosen]) ++chosen;
            if (chosen == used_colors) {
                color[v] = used_colors++;
            } else {
                color[v] = chosen;
            }
            // Update neighbours
            for (int to : graph[v]) {
                if (color[to] == -1) {
                    // Remove old entry
                    pq.erase({{-sat_degree[to], -degree[to]}, to});
                    // Update saturation
                    if (neighbor_colors[to].find(color[v]) == neighbor_colors[to].end()) {
                        neighbor_colors[to].insert(color[v]);
                        sat_degree[to] = static_cast<int>(neighbor_colors[to].size());
                    }
                    pq.insert({{-sat_degree[to], -degree[to]}, to});
                }
            }
        }
        return color;
}

int count_used_colors(const vector<int>& colors) {
    int used = 0;
    for (int c : colors) {
        used = max(used, c + 1);
    }
    return used;
}

vector<int> make_best_coloring(const vector<vector<int>>& graph,
                               const chrono::steady_clock::time_point& launch_time) {
    int n = static_cast<int>(graph.size());
    vector<int> best = greedy_coloring(graph);
    int best_colors = count_used_colors(best);

    uint64_t base_seed = static_cast<uint64_t>(chrono::high_resolution_clock::now().time_since_epoch().count());
    vector<int> b_values = {1, 2, 4, 6, 8, 15, 25, 40};
    sort(b_values.begin(), b_values.end());
    b_values.erase(unique(b_values.begin(), b_values.end()), b_values.end());

    int attempts = 200;
    int target_k = best_colors - 1;
    for (int attempt = 0; attempt < attempts && target_k >= 1; ++attempt) {
        int b = b_values[attempt % static_cast<int>(b_values.size())];
        int max_steps = 1000 * n;
        uint64_t seed = base_seed + static_cast<uint64_t>(attempt) * 0x9e3779b97f4a7c15ULL;
        Solver solver(n, 0, graph, target_k, seed);
        auto [used_colors, colors] = solver.FCNS(b, max_steps);
        if (static_cast<int>(colors.size()) != n) {
            // it means that the solver failed to color all vertices, so we skip this attempt
            continue;
        }

        bool complete = true;
        for (int v = 0; v < n; ++v) {
            if (colors[v] < 0) {
                complete = false;
                // it means that the solver failed to color all vertices, so we skip this attempt
                break;
            }
        }
        if (!complete) {
            continue;
        }
        --target_k;
        if (used_colors < best_colors) {
            best = std::move(colors);
            best_colors = used_colors;
            const double elapsed_seconds = chrono::duration<double>(
                chrono::steady_clock::now() - launch_time
            ).count();
            cerr << "{\"colors\": " << best_colors
                 << ", \"time\": " << elapsed_seconds << "}" << endl;
        }
    }

    return best;
}

}  // namespace

int main(int argc, char** argv) {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    const auto launch_time = chrono::steady_clock::now();

    int n, m;
    cin >> n >> m;
    vector<vector<int>> graph(n);
    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    vector<int> answer = make_best_coloring(graph, launch_time);
    int colors_used = count_used_colors(answer);

    cout << colors_used << '\n';
    for (int v = 0; v < n; ++v) {
        cout << answer[v] + 1 << ' ';
    }
    cout << '\n';
    return 0;
}

